import { NextFunction, Response } from "express";

import { ApiError } from "../utils/api-error";
import { logger } from "../utils/logger";
import User from "../models/user.model";
import { UserRequest } from "../types/user";
import { generateHashedToken } from "../helpers/token.helpers";
import Session from "../models/session.model";
import { SESSION_EXPIRES_IN } from "../constants/auth";

export async function verifyAuthentication(
  req: UserRequest,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const sid = req.cookies?.sid;
    const authorization = req.headers.authorization;
    const token = authorization?.split(" ")[1];

    if (!sid && !token) {
      return next(ApiError.unauthorized("Unauthorized, please login."));
    }

    const hashedSession = generateHashedToken(sid || token);

    const session = await Session.findOne({
      tokenHash: hashedSession,
      isActive: true,
      expiresAt: { $gt: new Date() }
    });

    if (!session) {
      return next(ApiError.unauthorized("Session expired."));
    }

    if (
      session.userAgent !== req.headers["user-agent"] ||
      session.ip !== req.ip
    ) {
      return next(ApiError.unauthorized("Invalid session."));
    }

    const user = await User.findById(session.userId);

    if (!user) {
      return next(ApiError.unauthorized("User not found."));
    }
    req.user = {
      _id: user._id.toString(),
      role: user.role
    };

    req.session = {
      _id: session._id.toString(),
      token: sid || token
    };

    const remainingTime = session.expiresAt.getTime() - Date.now();
    const EXTEND_THRESHOLD = SESSION_EXPIRES_IN * 0.25;

    if (remainingTime < EXTEND_THRESHOLD) {
      await Session.updateOne(
        { _id: session._id.toString() },
        {
          $set: {
            lastUsedAt: new Date(),
            expiresAt: new Date(Date.now() + SESSION_EXPIRES_IN)
          }
        }
      );
    }

    return next();
  } catch (error) {
    logger.error(error, "Authentication verification failed");
    return next(
      ApiError.server("Internal server error during authentication.")
    );
  }
}

import { Request, Response, NextFunction } from "express";
import z, { ZodError, type ZodObject } from "zod";

import { ApiError } from "../utils/api-error";

export const validateRequest = (schema: ZodObject<any>) => {
  return (req: Request, res: Response, next: NextFunction) => {
    try {
      schema.parse(req.body);

      next();
    } catch (error) {
      if (!(error instanceof ZodError)) {
        return next(error);
      }

      return next(
        ApiError.badRequest(
          "Invalid request data",
          z.flattenError(error).fieldErrors || z.flattenError(error)
        )
      );
    }
  };
};

import { isValidObjectId } from "mongoose";
import { ApiError } from "../utils/api-error";
import { NextFunction, Request, Response } from "express";

export const validateObjectId = (paramName: string = "id") => {
  return (req: Request, res: Response, next: NextFunction) => {
    const value =
      req?.params[paramName] || req?.body[paramName] || req?.query[paramName];
    if (!value) {
      throw ApiError.badRequest(`${paramName} is required`);
    }

    if (!isValidObjectId(value)) {
      throw ApiError.badRequest(`Invalid ${paramName}`);
    }

    next();
  };
};

import { NextFunction, Response } from "express";
import { UserRequest } from "../types/user";
import User from "../models/user.model";
import { ApiError } from "../utils/api-error";
import { logger } from "../utils/logger";

export async function checkUserAccountRestriction(
  req: UserRequest,
  _res: Response,
  next: NextFunction
): Promise<void> {
  try {
    if (!req.user?._id) {
      return next(ApiError.unauthorized("Unauthorized"));
    }

    const user = await User.findById(req.user._id);

    if (!user) {
      return next(ApiError.unauthorized("Unauthorized, please login."));
    }

    if (user.isDeleted || user.deletedAt) {
      return next(ApiError.forbidden("Your account has been deactivated."));
    }

    if (user.lockUntil && user.lockUntil.getTime() > Date.now()) {
      const minutesLeft = Math.ceil(
        (user.lockUntil.getTime() - Date.now()) / (1000 * 60)
      );

      return next(
        ApiError.forbidden(
          `Your account has been locked. Please try again after ${minutesLeft} minutes.`
        )
      );
    }

    if (!user.isEmailVerified) {
      return next(
        ApiError.forbidden("Email not verified. Please verify your email.")
      );
    }

    return next();
  } catch (err: any) {
    logger.error(err?.message || err);
    return next(ApiError.server("Something went wrong"));
  }
}

import multer from "multer";

export const ALLOWED_FILE_TYPES = [
  "image/jpeg",
  "image/png",
  "image/webp",
  "video/mp4",
  "video/mpeg",
  "video/quicktime",
  "application/pdf"
];

export const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

const storage = multer.memoryStorage();

const fileFilter: multer.Options["fileFilter"] = (_req, file, cb) => {
  if (!ALLOWED_FILE_TYPES.includes(file.mimetype)) {
    return cb(null, false);
  }
  cb(null, true);
};

const upload = multer({
  storage,
  limits: { fileSize: MAX_FILE_SIZE },
  fileFilter
});

export default upload;

import { NextFunction, Request, Response } from "express";
import cors from "cors";
import { Express } from "express";
import helmet from "helmet";
import env from "../configs/env";

export const configureSecurityHeaders = (app: Express) => {
  // Use Helmet to set various security-related HTTP headers
  app.use(helmet());

  // Configure CORS
  app.use(
    cors({
      origin: env.CORS_ORIGIN || "*",
      credentials: true,
      methods: ["GET", "POST", "PUT", "DELETE", "PATCH", "OPTIONS"],
      allowedHeaders: ["Content-Type", "Authorization", "X-Requested-With"]
    })
  );

  // Additional custom security headers
  app.use((req: Request, res: Response, next: NextFunction) => {
    res.setHeader("X-Content-Type-Options", "nosniff");
    res.setHeader("X-Frame-Options", "DENY");
    res.setHeader("X-XSS-Protection", "1; mode=block");
    next();
  });
};

import { NextFunction, Request, Response } from "express";
import { rateLimit } from "express-rate-limit";
import { STATUS_CODES } from "../constants/status-codes";
import { ApiError } from "../utils/api-error";

export const rateLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per window
  standardHeaders: true, // Return rate limit info in the `RateLimit-*` headers
  legacyHeaders: false, // Disable the `X-RateLimit-*` headers
  message: {
    success: false,
    message:
      "Too many requests from this IP, please try again after 15 minutes",
    status: 429
  },
  handler: (req: Request, res: Response, next: NextFunction, options: any) => {
    next(new ApiError(STATUS_CODES.TOO_MANY_REQUESTS, options.message.message));
  }
});

