import { NextFunction } from "express";
import { SignupUserType } from "./auth.validation";
import {
  LOGIN_MAX_ATTEMPTS,
  MAX_SESSIONS_PER_USER,
  REACTIVATION_AVAILABLE_AT,
  SESSION_EXPIRES_IN
} from "./auth.constants";

import mongoose from "mongoose";
import { OtpService } from "../otp/otp.service";
import { deleteFileFromCloudinary } from "../upload/upload.service";
import env from "../../shared/configs/env";
import { ApiError } from "@/shared/utils/api-error";
import User from "./user.model";
import Session from "./session.model";
import {
  generateHashedToken,
  generateSecureToken
} from "@/shared/helpers/token.helpers";
import { SendMail, sendEmail } from "@/shared/utils/send-mail";
import { hashPassword, verifyPassword } from "@/shared/helpers/auth.helpers";
import { IUser } from "./auth.types";

export type Context = {
  setAuthCookie?: (token: string) => void;
  ip?: string;
  userAgent?: string;
};

export class AuthService {
  static async registerUser(
    next: NextFunction,
    user: Omit<SignupUserType, "confirmPassword">
  ) {
    const { name, email, password, role } = user;
    const existingUser = await User.findOne({ email }).select("+password");

    if (existingUser) {
      return next(ApiError.conflict("User with this email already exists"));
    }

    const hashedPassword = await hashPassword(password);

    const newUser = await User.create({
      name,
      email,
      password: hashedPassword,
      role
    });

    return newUser;
  }

  static async loginAndSendOtp(
    next: NextFunction,
    { email, password }: { email: string; password: string }
  ) {
    const session = await mongoose.startSession();

    try {
      session.startTransaction();

      const user = await User.findOne({ email })
        .session(session)
        .select("+password");
      if (!user) {
        await session.abortTransaction();
        return next(ApiError.unauthorized("Invalid credentials"));
      }

      const isPasswordValid = await verifyPassword(
        password,
        user.password || ""
      );
      if (!isPasswordValid) {
        await session.abortTransaction();
        return next(ApiError.unauthorized("Invalid credentials"));
      }

      const otp = await OtpService.sendOtp(next, {
        email,
        otpType: "signin",
        subject: "Signin"
      });

      if (!otp) {
        await session.abortTransaction();
        return next(ApiError.server("Failed to generate OTP"));
      }

      await session.commitTransaction();
      session.endSession();

      return {
        message: otp.message
      };
    } catch (err) {
      await session.abortTransaction();
      session.endSession();
      return next(ApiError.server("Signin failed"));
    }
  }

  static async handleToken(
    user: Pick<IUser, "isEmailVerified" | "_id" | "role" | "email">,
    context: Context
  ) {
    if (!user.isEmailVerified) {
      await User.updateOne(
        { _id: user._id },
        { $set: { isEmailVerified: true } }
      );
    }

    if (context.userAgent) {
      const existingDevice = await Session.findOne({
        userId: user._id,
        userAgent: context.userAgent
      });

      const isNewDevice = !existingDevice;
      if (isNewDevice) {
        const html = `
        <p>New sign-in to your account from a new device or browser.</p>
        <p>This could be a sign of a possible security threat.</p>
        <p> 
          <strong>Device:</strong> ${context.userAgent}<br/>
          <strong>IP Address:</strong> ${context.ip || "Unknown"}<br/>
          <strong>Time:</strong> ${new Date().toDateString()}<br/>
        </p>
        <p>If this was you, you can safely ignore this email. If not, please secure your account immediately.</p>
        `;

        await sendEmail({
          from: env.EMAIL_FROM,
          email: user.email,
          subject: "New Sign-in Alert",
          html
        } as SendMail);
      }
    }

    const token = generateSecureToken();
    const hashedToken = generateHashedToken(token);
    const activeSessions = await Session.countDocuments({
      userId: user._id,
      isActive: true
    });

    if (activeSessions >= MAX_SESSIONS_PER_USER) {
      await Session.findOneAndUpdate(
        { userId: user._id, isActive: true },
        { isActive: false },
        { sort: { lastUsedAt: 1 } }
      );
    }

    await Session.create({
      userId: user._id,
      tokenHash: hashedToken,
      expiresAt: new Date(Date.now() + SESSION_EXPIRES_IN),
      ip: context.ip,
      userAgent: context.userAgent,
      isActive: true
    });

    context.setAuthCookie && context.setAuthCookie(token);

    await User.updateOne(
      { _id: user._id },
      {
        $set: { lastLogin: new Date(), failedLoginAttempts: 0 },
        $unset: { lockUntil: 1 }
      }
    );
    return { message: "OTP verified and user signed in successfully" };
  }

  static async getUserProfile(userId: string) {
    const user = await User.findById(userId);
    return user;
  }

  static async forgotPassword(next: NextFunction, email: string) {
    const user = await User.findOne({ email });

    if (!user) {
      return next(
        ApiError.badRequest("If this email is registered, check your inbox.")
      );
    }

    const result = await OtpService.sendOtp(next, {
      email,
      otpType: "password-reset",
      subject: "Password Reset"
    });

    if (!result) {
      return next(ApiError.server("Failed to send otp!"));
    }

    return result;
  }

  static async resetPassword(
    next: NextFunction,
    email: string,
    newPassword: string
  ) {
    const user = await User.findOne({ email }).select("+password");

    if (!user) {
      return next(ApiError.unauthorized("Unauthorized access"));
    }

    if (user.lockUntil && new Date(user.lockUntil) > new Date()) {
      return next(
        ApiError.forbidden(
          `Your account has been locked. Please try again after ${Math.ceil(
            (user.lockUntil.getTime() - Date.now()) / (1000 * 60)
          )} minutes.`
        )
      );
    }

    if (user.failedLoginAttempts >= LOGIN_MAX_ATTEMPTS && user.lockUntil) {
      return next(
        ApiError.forbidden(
          `You have exceeded the maximum number of login attempts. Please try again after ${Math.ceil(
            (user.lockUntil.getTime() - Date.now()) / (1000 * 60)
          )} minutes.`
        )
      );
    }

    if (!user.isEmailVerified) {
      return next(ApiError.unauthorized("Please verify your email first."));
    }

    const oldPassword = user.password;

    const isOldPassword = await verifyPassword(
      newPassword,
      oldPassword as string
    );

    if (isOldPassword) {
      return next(ApiError.badRequest("New password should be different!"));
    }

    const hashedPassword = await hashPassword(newPassword);
    await User.updateOne(
      { email },
      {
        $set: {
          password: hashedPassword,
          isEmailVerified: true
        }
      }
    );
    return { message: "Password reset successfully!" };
  }

  static async changePassword(
    next: NextFunction,
    {
      newPassword,
      oldPassword,
      userId
    }: { userId: string; newPassword: string; oldPassword: string }
  ) {
    const user = await User.findById(userId).select("+password");
    if (!user) {
      return next(ApiError.unauthorized("Unauthorized access"));
    }

    if (!user.isEmailVerified) {
      return next(ApiError.unauthorized("Please verify your email first."));
    }

    const isOldPassword = await verifyPassword(
      oldPassword,
      user.password || ""
    );

    if (!isOldPassword) {
      return next(ApiError.unauthorized("Invalid credentials"));
    }

    if (newPassword === oldPassword) {
      return next(ApiError.badRequest("New password should be different!"));
    }

    const hashedPassword = await hashPassword(newPassword);
    await User.updateOne(
      { _id: userId },
      {
        $set: {
          password: hashedPassword
        }
      }
    );
    return { message: "Password changed successfully. Please login again!" };
  }

  static async deleteOrDeactiveAccount(
    next: NextFunction,
    userId: string,
    type: "soft" | "hard"
  ) {
    const user = await User.findById(userId);
    if (!user) {
      return next(ApiError.unauthorized("Unauthorized access"));
    }

    if (type === "soft") {
      user.isDeleted = true;
      user.deletedAt = new Date();
      user.reActivateAvailableAt = new Date(
        Date.now() + REACTIVATION_AVAILABLE_AT
      );
      await user.save();
    } else if (type === "hard") {
      if (user?.avatar?.public_id) {
        await deleteFileFromCloudinary([user.avatar.public_id]);
      }
      await User.findOneAndDelete({ _id: userId });
      await user.save();
    }
  }

  static async reactivateAccount(next: NextFunction, userId: string) {
    const user = await User.findById(userId);
    if (!user) {
      return next(ApiError.unauthorized("Unauthorized access"));
    }

    if (user.lockUntil && new Date(user.lockUntil) > new Date()) {
      return next(
        ApiError.badRequest(
          `Your account has been locked. Please try again after ${Math.ceil(
            (user.lockUntil.getTime() - Date.now()) / (1000 * 60)
          )} minutes.`
        )
      );
    }

    if (!user?.isDeleted || !user?.deletedAt) {
      return next(ApiError.badRequest("Your account is already active!"));
    }

    if (
      user?.reActivateAvailableAt &&
      new Date(user?.reActivateAvailableAt) > new Date()
    ) {
      return next(
        ApiError.forbidden(
          `Your account has been locked. Please try again after ${Math.ceil(
            (user.reActivateAvailableAt.getTime() - Date.now()) / (1000 * 60)
          )} minutes.`
        )
      );
    }

    await User.findOneAndUpdate(
      { _id: userId },
      {
        $set: {
          isDeleted: false,
          deletedAt: null,
          reActivateAvailableAt: null
        }
      },
      { new: true }
    );

    await user.save();
  }

  static async getUserSessions(userId: string) {
    const session = await Session.aggregate([
      {
        $match: { userId: new mongoose.Types.ObjectId(userId), isActive: true }
      },
      {
        $project: {
          _id: 1,
          ip: 1,
          userAgent: 1,
          lastUsedAt: 1,
          expiresAt: 1,
          isActive: 1,
          userId: 1
        }
      },
      {
        $lookup: {
          from: "users",
          localField: "userId",
          foreignField: "_id",
          as: "user",
          pipeline: [
            {
              $project: {
                _id: 1,
                name: 1,
                email: 1
              }
            }
          ]
        }
      },
      {
        $unwind: {
          path: "$user",
          preserveNullAndEmptyArrays: true
        }
      }
    ]);
    return session;
  }

  static async deleteUserSession(userId: string, sessionId: string) {
    return await Session.findOneAndDelete({
      userId,
      _id: sessionId
    });
  }

  static async logoutUser(userId: string, sessionId: string) {
    return await Session.deleteMany({ userId, _id: sessionId });
  }

  static async deleteAllUserSessions(userId: string) {
    return await Session.findOneAndDelete({
      userId
    });
  }
}

import { Router } from "express";
import { validateRequest } from "../../shared/middlewares/validate-request";
import {
  ChangePasswordSchema,
  DeleteAccountSchema,
  RequestOtpSchema,
  ResetPasswordSchema,
  SigninSchema,
  SignupSchema,
  UpdateProfileSchema,
  VerifyOtpSchema
} from "./auth.validation";
import {
  changePassword,
  deleteAccount,
  deleteAllUserSessions,
  deleteUserSession,
  forgotPassword,
  getUserProfile,
  getUserSessions,
  logoutUser,
  reactivateAccount,
  resetPassword,
  signinUser,
  signupUser,
  updateProfile,
  verifyOtp
} from "./auth.controller";
import { verifyAuthentication } from "../../shared/middlewares/verify-auth";
import { checkUserAccountRestriction } from "../../shared/middlewares/user-account-restriction";
import {
  changePasswordLimiter,
  deleteAccountLimiter,
  otpRequestLimiter,
  otpVerificationLimiter,
  resetPasswordLimiter,
  signinRateLimiter,
  signupRateLimiter
} from "../../shared/middlewares/rate-limiter";
import upload from "../../shared/middlewares/upload-file";
import { validateObjectId } from "../../shared/middlewares/validate-id";

const router = Router();

router.post(
  "/verify-otp",
  validateRequest(VerifyOtpSchema),
  otpVerificationLimiter,
  verifyOtp
);

router.post(
  "/signup",
  validateRequest(SignupSchema),
  signupRateLimiter,
  signupUser
);

router.post(
  "/signin",
  validateRequest(SigninSchema),
  signinRateLimiter,
  signinUser
);

router.get("/profile", verifyAuthentication, getUserProfile);

router.get("/sessions", verifyAuthentication, getUserSessions);

router.delete("/sessions", verifyAuthentication, deleteAllUserSessions);

router.delete(
  "/sessions/:sessionId",
  validateObjectId("sessionId"),
  verifyAuthentication,
  deleteUserSession
);

router.patch(
  "/profile",
  upload.single("avatar"),
  validateRequest(UpdateProfileSchema),
  verifyAuthentication,
  checkUserAccountRestriction,
  updateProfile
);

router.post(
  "/logout",
  verifyAuthentication,
  checkUserAccountRestriction,
  logoutUser
);

router.post(
  "/forgot-password",
  validateRequest(RequestOtpSchema.pick({ email: true })),
  otpRequestLimiter,
  forgotPassword
);

router.post(
  "/reset-password",
  validateRequest(ResetPasswordSchema),
  resetPasswordLimiter,
  resetPassword
);

router.post(
  "/change-password",
  verifyAuthentication,
  validateRequest(ChangePasswordSchema),
  checkUserAccountRestriction,
  changePasswordLimiter,
  changePassword
);

router.delete(
  "/delete-account",
  verifyAuthentication,
  validateRequest(DeleteAccountSchema),
  checkUserAccountRestriction,
  deleteAccountLimiter,
  deleteAccount
);

router.put("/reactivate-account", verifyAuthentication, reactivateAccount);

export default router;

import { NextFunction, Request, Response } from "express";
import { ApiResponse } from "../../shared/utils/api-response";
import { AsyncHandler } from "../../shared/utils/async-handler";

import { ApiError } from "../../shared/utils/api-error";
import { AuthService } from "./auth.service";
import { OtpService } from "../otp/otp.service";
import { clearCookie, setCookies } from "../../shared/helpers/cookie.helper";
import {
  deleteFileFromCloudinary,
  uploadToCloudinary
} from "../upload/upload.service";
import {
  RESET_PASSWORD_TOKEN_EXPIRY,
  SESSION_EXPIRES_IN
} from "./auth.constants";
import { DeleteAccountType, VerifyOtpType } from "./auth.validation";
import { UserRequest } from "@/types/global";

//? VERIFY OTP
export const verifyOtp = AsyncHandler(
  async (req: Request, res: Response, next: NextFunction) => {
    const { email, otpCode, otpType }: VerifyOtpType = req.body;
    if (!email || !otpCode || !otpType) {
      return next(
        ApiError.badRequest("Email, OTP code and OTP type are required")
      );
    }

    const otp = await OtpService.verifyOtp(
      next,
      { email, otpCode, otpType },
      {
        setAuthCookie: (token: string) => {
          setCookies(res, [
            {
              cookie: "sid",
              value: token,
              maxAge: SESSION_EXPIRES_IN
            }
          ]);
        },
        ip: req.ip || "unknown",
        userAgent: req.headers["user-agent"] || ""
      },
      {
        setCookie: (token: string) => {
          setCookies(res, [
            {
              cookie: "resetPasswordToken",
              value: token,
              maxAge: RESET_PASSWORD_TOKEN_EXPIRY
            }
          ]);
        }
      }
    );

    if (!otp) {
      return next(ApiError.server("Failed to verify OTP!"));
    }

    return ApiResponse.ok(res, otp?.message || "OTP verified successfully!");
  }
);

//? SIGNUP USER
export const signupUser = AsyncHandler(
  async (req: Request, res: Response, next: NextFunction) => {
    const { name, email, password, role } = req.body;
    if (!name || !email || !password) {
      return next(ApiError.badRequest("Name, email and password are required"));
    }

    const user = await AuthService.registerUser(next, {
      name,
      email,
      password,
      role
    });

    if (!user) {
      return next(ApiError.server("Failed to register user!"));
    }

    return ApiResponse.created(res, "User registered successfully", {
      name: user.name,
      email: user.email,
      role: user.role
    });
  }
);

//? SIGNIN USER
export const signinUser = AsyncHandler(
  async (req: Request, res: Response, next: NextFunction) => {
    const { email, password } = req.body;
    if (!email || !password) {
      return next(ApiError.badRequest("Email and password are required"));
    }

    const result = await AuthService.loginAndSendOtp(next, { email, password });

    if (!result) {
      return next(ApiError.server("Failed to login!"));
    }

    return ApiResponse.ok(res, result.message || "Otp sent successfully!");
  }
);

//? GET USER PROFILE
export const getUserProfile = AsyncHandler(
  async (req: UserRequest, res: Response, next: NextFunction) => {
    const userId = req.user?._id;
    if (!userId) {
      return next(ApiError.unauthorized("Unauthorized access"));
    }

    const user = await AuthService.getUserProfile(userId.toString());
    if (!user) {
      return next(ApiError.notFound("User not found"));
    }

    if (user.isDeleted) {
      return next(ApiError.notFound("This account has been deactivated."));
    }

    return ApiResponse.ok(res, "User profile fetched successfully", {
      user: {
        _id: user._id,
        name: user.name,
        email: user.email,
        role: user.role,
        avatar: user.avatar,
        isEmailVerified: user.isEmailVerified,
        lastLoginAt: user.lastLoginAt
      }
    });
  }
);

//? UPDATE PROFILE
export const updateProfile = AsyncHandler(
  async (req: UserRequest, res: Response, next: NextFunction) => {
    const data = req.body;
    const { name } = data;

    if (!req.user?._id) {
      return next(ApiError.unauthorized("Unauthorized access"));
    }

    const user = await AuthService.getUserProfile(req.user?._id.toString());

    if (!user) {
      return next(ApiError.notFound("User not found"));
    }

    if (req?.file && user?.avatar?.public_id) {
      await deleteFileFromCloudinary([user.avatar.public_id]);
    }

    if (req?.file && user?.avatar) {
      const file = await uploadToCloudinary(req.file.buffer, {
        folder: "uploads/files",
        resource_type: "auto"
      });
      user.avatar = {
        public_id: req.file
          ? file.public_id
          : (user?.avatar?.public_id as string),
        url: req.file ? file.url : (user.avatar.url as string),
        size: req.file ? file.size : (user.avatar.size as number)
      };
    }

    if (name) {
      user.name = name;
    }

    await user.save();

    return ApiResponse.Success(res, "Profile updated successfully!", user);
  }
);

//? LOGOUT
export const logoutUser = AsyncHandler(
  async (req: UserRequest, res: Response, next: NextFunction) => {
    const userId = req.user?._id;
    if (!userId) {
      return next(ApiError.unauthorized("Unauthorized access"));
    }

    const currentSessionId = req.session?._id;
    if (!currentSessionId) {
      return next(ApiError.unauthorized("Unauthorized access"));
    }

    await AuthService.logoutUser(userId.toString(), currentSessionId);

    clearCookie(res, "sid");

    return ApiResponse.Success(res, "Logged out successfully!");
  }
);

//? FORGOT PASSWORD
export const forgotPassword = AsyncHandler(
  async (req: Request, res: Response, next: NextFunction) => {
    const { email } = req.body;
    if (!email) {
      return next(ApiError.badRequest("Email is required!"));
    }

    const result = await AuthService.forgotPassword(next, email);

    if (!result) {
      return next(ApiError.server("Failed to send otp!"));
    }

    return ApiResponse.ok(res, result.message || "Otp sent successfully!");
  }
);

//? RESET PASSWORD
export const resetPassword = AsyncHandler(
  async (req: UserRequest, res: Response, next: NextFunction) => {
    const { newPassword, email } = req.body;
    if (!email || !newPassword) {
      return next(ApiError.badRequest("Newpassword and email are required!"));
    }

    const hashedResetPasswordToken = req.cookies?.hashedResetPasswordToken;

    if (!hashedResetPasswordToken) {
      return next(
        ApiError.badRequest("Reset password token not found or expired")
      );
    }

    const result = await AuthService.resetPassword(next, email, newPassword);

    if (!result) {
      return next(ApiError.server("Failed to reset password!"));
    }

    res.clearCookie("hashedResetPasswordToken");
    return ApiResponse.ok(
      res,
      result.message || "Password reset successfully!"
    );
  }
);

//? CHANGE PASSWORD
export const changePassword = AsyncHandler(
  async (req: UserRequest, res: Response, next: NextFunction) => {
    const userId = req?.user?._id;

    if (!userId) {
      return next(ApiError.unauthorized("Unauthorized access"));
    }

    const { oldPassword, newPassword } = req.body;

    if (!oldPassword || !newPassword) {
      return next(
        ApiError.badRequest("Old password and new password are required")
      );
    }

    const result = await AuthService.changePassword(next, {
      userId: userId.toString(),
      oldPassword,
      newPassword
    });

    if (!result) {
      return next(ApiError.server("Failed to change password!"));
    }

    clearCookie(res, "sid");

    return ApiResponse.ok(
      res,
      result.message || "Password changed successfully!"
    );
  }
);

//? DELETE/DEACTIVATE ACCOUNT
export const deleteAccount = AsyncHandler(
  async (req: UserRequest, res: Response, next: NextFunction) => {
    const { userId, type }: DeleteAccountType = req.body;

    if (!userId || !type) {
      return next(ApiError.badRequest("User id and type are required!"));
    }

    const reqUserId = req?.user?._id;

    if (!reqUserId) {
      return next(ApiError.unauthorized("Unauthorized access"));
    }

    if (userId !== reqUserId) {
      return next(
        ApiError.unauthorized("you are not authorized to perform this action")
      );
    }

    await AuthService.deleteOrDeactiveAccount(next, userId, type);

    if (type === "hard") {
      clearCookie(res, "sid");
    }

    return ApiResponse.Success(
      res,
      `Account ${type === "soft" ? "deactivated" : "deleted"} successfully!`
    );
  }
);

//? REACTIVATE ACCOUNT
export const reactivateAccount = AsyncHandler(
  async (req: UserRequest, res: Response, next: NextFunction) => {
    const userId = req?.user?._id;

    if (!userId) {
      return next(ApiError.unauthorized("Unauthorized access"));
    }

    await AuthService.reactivateAccount(next, userId);

    return ApiResponse.Success(res, "Account reactivated successfully!");
  }
);

//? GET USER SESSIONS
export const getUserSessions = AsyncHandler(
  async (req: UserRequest, res: Response, next: NextFunction) => {
    const userId = req?.user?._id;
    const currentSessionId = req.session?._id;

    if (!userId || !currentSessionId) {
      return next(ApiError.unauthorized("Unauthorized access"));
    }

    const result = await AuthService.getUserSessions(userId.toString());

    if (!result) {
      return next(ApiError.server("Failed to get user sessions!"));
    }

    return ApiResponse.ok(res, "User sessions fetched successfully", result);
  }
);

//? DELETE SESSION
export const deleteUserSession = AsyncHandler(
  async (req: UserRequest, res: Response, next: NextFunction) => {
    const userId = req?.user?._id;
    const { sessionId } = req.params;

    if (!userId || !sessionId) {
      return next(ApiError.unauthorized("Unauthorized access"));
    }

    const result = await AuthService.deleteUserSession(
      userId,
      sessionId as string
    );

    if (!result) {
      return next(ApiError.server("Failed to delete user session!"));
    }

    const reqSId = req.cookies?.sid;

    const isCurrentSession = sessionId === reqSId;
    if (isCurrentSession) {
      clearCookie(res, "sid");
    }

    return ApiResponse.Success(res, "User session deleted successfully!");
  }
);

//? DELETE ALL SESSIONS
export const deleteAllUserSessions = AsyncHandler(
  async (req: UserRequest, res: Response, next: NextFunction) => {
    const userId = req?.user?._id;

    if (!userId) {
      return next(ApiError.unauthorized("Unauthorized access"));
    }

    const result = await AuthService.deleteAllUserSessions(userId);

    if (!result) {
      return next(ApiError.server("Failed to delete user sessions!"));
    }

    res.clearCookie("sid");

    return ApiResponse.Success(res, "User sessions deleted successfully!");
  }
);

